import axios from 'axios';

// 使用相对路径，通过Vue代理转发
const API_BASE_URL = '/api';

console.log('API Base URL:', API_BASE_URL);

// 创建axios实例
const apiClient = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
  timeout: 30000
});

// 添加响应拦截器
apiClient.interceptors.response.use(
  response => response.data, // 自动解析response.data
  error => {
    console.error('API请求失败:', error);
    
    // 开发环境下提供模拟数据
    if (process.env.NODE_ENV === 'development') {
      const mockData = getMockData(error.config);
      if (mockData) {
        console.warn('使用模拟数据');
        return Promise.resolve(mockData);
      }
    }
    
    return Promise.reject(error);
  }
);

// 根据请求获取模拟数据
function getMockData(config) {
  const { url, method } = config;
  
  // 小说列表
  if (url === '/novels' && method === 'get') {
    return {
      novels: [
        { 
          id: 1, 
          title: '修真世界', 
          author: '梦入神机',
          processingStatus: 'COMPLETED', 
          processedChapters: 10, 
          totalChapters: 10,
          description: '一个普通少年偶然获得远古传承，逐步成长为修真界顶尖强者的故事。'
        },
        { 
          id: 2, 
          title: '未来科技城', 
          author: '星辰大海',
          processingStatus: 'COMPLETED', 
          processedChapters: 50, 
          totalChapters: 50,
          description: '2150年，人类建立了第一座智能城市，但随着AI的发展，一系列惊人的变故开始发生...'
        }
      ]
    };
  }
  
  // 小说详情
  if (url.match(/\/novels\/\d+$/) && method === 'get') {
    const id = parseInt(url.split('/').pop());
    return {
      id,
      title: id === 1 ? '修真世界' : '未来科技城',
      author: id === 1 ? '梦入神机' : '星辰大海',
      processingStatus: 'COMPLETED',
      description: id === 1 
        ? '一个普通少年偶然获得远古传承，逐步成长为修真界顶尖强者的故事。'
        : '2150年，人类建立了第一座智能城市，但随着AI的发展，一系列惊人的变故开始发生...',
      overallSummary: id === 1 
        ? '这本小说主要讲述了林逸、张小凡等人物在修真世界中的成长故事。'
        : '这本小说主要讲述了李明、周思琪等人物在未来世界中对抗AI危机的故事。',
      worldBuildingSummary: id === 1
        ? '修真世界建立在五行相生相克的基础上，分为炼气、筑基、金丹、元婴等多个境界。'
        : '故事发生在2150年，城市中的一切都由中央智能系统"天眼"控制。',
      characterDevelopmentSummary: id === 1
        ? '主角林逸性格坚毅执着，遇到挫折不轻言放弃，逐渐成长为有担当的强者。'
        : '主角李明是程序设计师，性格沉稳理性；女主角周思琪是人工智能伦理学家。',
      chapters: [
        { id: 1, chapterNumber: 1, title: '第一章', summary: '章节摘要内容', keywords: ['关键词1', '关键词2', '关键词3'] },
        { id: 2, chapterNumber: 2, title: '第二章', summary: '章节摘要内容', keywords: ['关键词1', '关键词2', '关键词3'] },
        { id: 3, chapterNumber: 3, title: '第三章', summary: '章节摘要内容', keywords: ['关键词1', '关键词2', '关键词3'] }
      ],
      tags: [
        { id: 1, type: 'POSITIVE', name: id === 1 ? '修真升级' : '科技感强' },
        { id: 2, type: 'POSITIVE', name: id === 1 ? '世界观完善' : '深度思考' },
        { id: 3, type: 'WARNING', name: id === 1 ? '套路化情节' : '技术术语多' },
        { id: 4, type: 'INFO', name: id === 1 ? '修真知识门槛' : '未来科技背景' }
      ]
    };
  }
  
  // 小说状态
  if (url.match(/\/novels\/\d+\/status$/) && method === 'get') {
    return {
      status: 'COMPLETED',
      processedChapters: 10,
      totalChapters: 10
    };
  }
  
  // 上传小说
  if (url.includes('/novels/upload') && method === 'post') {
    return {
      id: 3,
      status: 'PROCESSING',
      message: '文件已上传，开始处理'
    };
  }
  
  return null;
}

export default {
  // 获取小说列表
  async getNovelList() {
    return apiClient.get('/novels');
  },

  // 获取小说详情
  async getNovelDetail(novelId) {
    if (!novelId) {
      throw new Error('小说ID不能为空');
    }
    return apiClient.get(`/novels/${novelId}`);
  },

  // 获取小说处理状态
  async getNovelStatus(novelId) {
    if (!novelId) {
      throw new Error('小说ID不能为空');
    }
    return apiClient.get(`/novels/${novelId}/status`);
  },

  // 上传小说
  async uploadNovel(formData) {
    const headers = { 'Content-Type': 'multipart/form-data' };
    return apiClient.post('/novels/upload', formData, { headers });
  },

  // 获取小说摘要分析
  async getSummaryAnalysis(novelId) {
    if (!novelId) {
      throw new Error('小说ID不能为空');
    }
    return apiClient.get(`/novels/${novelId}/summary`);
  },

  // 获取小说章节列表
  async getChapterList(novelId) {
    if (!novelId) {
      throw new Error('小说ID不能为空');
    }
    return apiClient.get(`/novels/${novelId}/chapters`);
  },

  // 获取标签分析
  async getTagAnalysis(novelId) {
    if (!novelId) {
      throw new Error('小说ID不能为空');
    }
    return apiClient.get(`/novels/${novelId}/tags`);
  },

  // 获取数据可视化
  async getVisualizations(novelId) {
    if (!novelId) {
      throw new Error('小说ID不能为空');
    }
    return apiClient.get(`/novels/${novelId}/visualizations`);
  }
}
